using System.Threading.Tasks;

public sealed class Cache
{
    public async ValueTask<int> LoadTwiceAsync()
    {
        ValueTask<int> value = ReadAsync();
        int first = await value;
        int second = await value;
        return first + second;
    }

    private static ValueTask<int> ReadAsync() => ValueTask.FromResult(1);
}

using System.Threading.Tasks;

public sealed class Cache
{
    public async ValueTask<int> LoadTwiceAsync()
    {
        int first = await ReadAsync();
        int second = await ReadAsync();
        return first + second;
    }

    private static ValueTask<int> ReadAsync() => ValueTask.FromResult(1);
}
